export const viewerHtml = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <title>Atlas Architecture Map</title>
  <link rel="stylesheet" href="style.css">
</head>
<body>
  <header class="topbar">
    <div class="identity">
      <button id="back" class="icon-button" data-tooltip="Return to the previously selected item" aria-label="Back" disabled>&larr;</button>
      <strong>Atlas</strong>
      <span id="project-name">Architecture Map</span>
      <span id="context-label" hidden></span>
    </div>
    <div id="graph-controls" class="toolbar" hidden>
      <button id="fit" data-tooltip="Center the current map at a readable scale">Fit view</button>
      <button id="zoom-in" class="icon-button" data-tooltip="Zoom in" aria-label="Zoom in">+</button>
      <button id="zoom-out" class="icon-button" data-tooltip="Zoom out" aria-label="Zoom out">-</button>
    </div>
  </header>
  <div class="app-shell">
    <aside class="sidebar">
      <div class="search-box">
        <label for="search">Find in project</label>
        <input id="search" type="search" placeholder="Route, service, file..." autocomplete="off">
        <div id="search-results" class="search-results" hidden></div>
      </div>
      <nav id="modes" class="mode-nav" aria-label="Architecture views"></nav>
      <div class="sidebar-project">
        <span id="stack-name"></span>
        <small id="scan-date"></small>
      </div>
    </aside>
    <main class="content">
      <section id="overview" class="overview"></section>
      <section id="explorer" class="explorer" hidden>
        <header class="explorer-header">
          <div>
            <span class="eyebrow">Explore architecture</span>
            <h1 id="view-title"></h1>
            <p id="view-description" class="view-description"></p>
          </div>
          <div id="view-filters" class="type-filters" aria-label="Node type filters"></div>
        </header>
        <div class="explorer-grid">
          <aside class="catalog">
            <div class="catalog-heading"><strong id="catalog-title"></strong><span id="catalog-count"></span></div>
            <input id="catalog-search" type="search" placeholder="Filter current view..." autocomplete="off">
            <div id="catalog-list" class="catalog-list"></div>
            <div id="catalog-footer" class="catalog-footer"></div>
          </aside>
          <section class="graph-pane">
            <div id="graph-guide" class="graph-guide" hidden>
              <span>Used by</span><strong>Selected</strong><span>Depends on</span><span></span><span></span>
            </div>
            <div class="graph-status"><span id="graph-status"></span><button id="clear-focus" hidden>Clear focus</button></div>
            <div id="cy"></div>
            <div id="empty" class="empty-state" hidden>No matching architecture entities.</div>
            <div id="tooltip" class="tooltip" hidden></div>
            <button id="graph-help" class="graph-help" data-tooltip="How to read and navigate this map" aria-label="How to use the map" aria-expanded="false">?</button>
            <div id="graph-help-panel" class="graph-help-panel" hidden>
              <div class="graph-help-heading"><strong>How to read this map</strong><button id="graph-help-close" class="icon-button" aria-label="Close map help">&times;</button></div>
              <div class="graph-help-row"><b>1</b><span><strong>Select a box</strong><small>See what it does and everything directly connected to it.</small></span></div>
              <div class="graph-help-row"><b>2</b><span><strong>Follow the arrow</strong><small>The box at the start uses, calls, reads, or sends something to the box at the arrow.</small></span></div>
              <div class="graph-help-row"><b>3</b><span><strong>Hover a line</strong><small>Atlas explains the exact relationship and highlights both ends.</small></span></div>
              <div class="graph-help-shortcuts">Drag to move &middot; Wheel to zoom &middot; Double-click the background to fit</div>
            </div>
            <div id="legend" class="legend"></div>
          </section>
        </div>
      </section>
    </main>
    <aside id="details" class="details" hidden>
      <button id="details-close" class="icon-button close-button" title="Close details" aria-label="Close details">&times;</button>
      <div id="details-content"></div>
    </aside>
  </div>
  <div id="ui-tooltip" class="tooltip ui-tooltip" role="tooltip" hidden></div>
  <script src="cytoscape.min.js"></script>
  <script src="graph-data.js"></script>
  <script src="app.js"></script>
</body>
</html>`;

