  if (!rawGraph || !Array.isArray(rawGraph.nodes) || !Array.isArray(rawGraph.edges)) throw new Error('Atlas graph data is missing or invalid.');
  var nodes = rawGraph.nodes.filter(function(node){return node && typeof node.id === 'string' && typeof node.type === 'string';});
  var nodeMap = new Map(nodes.map(function(node){return [node.id,node];}));
  var edges = rawGraph.edges.filter(function(edge){return edge && nodeMap.has(edge.from) && nodeMap.has(edge.to);});
  var incoming = new Map(), outgoing = new Map();
  nodes.forEach(function(node){incoming.set(node.id,[]);outgoing.set(node.id,[]);});
  edges.forEach(function(edge){outgoing.get(edge.from).push(edge);incoming.get(edge.to).push(edge);});
  var colors={project:'#17201d',module:'#bd4e86',controller:'#286aa6',service:'#7452a8',provider:'#765d97',repository:'#5068a4',route:'#df642d',method:'#56635e',function:'#56635e',database:'#1e8068',table:'#1e8068',model:'#1e8068',entity:'#2b8d70',column:'#5b9f87',dto:'#16798b',external_api:'#c94747',environment_variable:'#b27a12',risk:'#c93f3f',test:'#6f7774',file:'#39433f',folder:'#66716d',config:'#8a6f3d',library:'#4e7184',guard:'#43635b',pipe:'#16798b',interceptor:'#755381',middleware:'#756b56',decorator:'#8c5375',package:'#3f5550',message_broker:'#293b75',message_topic:'#0f7895',queue:'#a66708',processor:'#6e4a9e'};
