  function renderSearchResults(){var needle=search.value.trim().toLowerCase();searchResults.innerHTML='';searchResults.hidden=!needle;if(!needle)return;var found=nodes.filter(function(node){return searchable(node).includes(needle);}).sort(function(a,b){return searchScore(b,needle)-searchScore(a,needle);}).slice(0,30);if(!found.length){searchResults.innerHTML='<div class="notice">No results.</div>';return;}found.forEach(function(node){var button=document.createElement('button');button.innerHTML='<strong><i class="type-dot '+typeClass(node.type)+'"></i>'+escapeHtml(node.label)+'</strong><small>'+escapeHtml(displayType(node.type)+(node.file?' / '+node.file:''))+'</small>';button.onclick=function(){search.value='';searchResults.hidden=true;revealNode(node.id,true);};searchResults.appendChild(button);});}
